import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { DepartmentDto, WorkTimeReportRow } from '../../../services/ns/models';
import styles from '../../../styles/erpPage.module.css';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({ value: String(i + 1), label: `T${i + 1}` }));
const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({ value: String(y), label: String(y) }));

const BaoCaoCongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [departmentId, setDepartmentId] = useState('');
  const [depts, setDepts] = useState<DepartmentDto[]>([]);
  const [rows, setRows] = useState<WorkTimeReportRow[]>([]);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService.getDepartments().then(d => { if (!cancelled) setDepts(d); }).catch(() => {});
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getWorkTimeReport({ month, year, departmentId: departmentId || undefined })
        .then(data => { if (!cancelled) setRows(data); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải báo cáo công', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year, departmentId, dispatch]);

  const totalOT = rows.reduce((s, r) => s + (r.overtimeHours ?? 0), 0);
  const avgRate = rows.length
    ? rows.reduce((s, r) => s + (r.attendanceRate ?? 0), 0) / rows.length
    : 0;

  const handleExport = () => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    if (departmentId) qs.set('departmentId', departmentId);
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/attendance/work-time-report/export-excel?${qs}`;
    a.download = `ChamCong-T${month}-${year}.xlsx`;
    a.click();
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-calendar-check" /> Báo cáo thời gian làm việc T{month}/{year}</h1>
          <p className={styles.subtitle}>
            {rows.length} nhân viên · Tổng tăng ca: {totalOT.toFixed(1)}h · Chuyên cần TB: {avgRate.toFixed(1)}%
          </p>
        </div>
        <div className={styles.headerActions}>
          <Select value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
          <Select value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Select
            value={departmentId}
            onChange={e => setDepartmentId(e.target.value)}
            options={[{ value: '', label: 'Tất cả đơn vị' }, ...depts.map(d => ({ value: d.id, label: `${d.code} — ${d.name}` }))]}
            size="small"
          />
          <Button variant="secondary" onClick={handleExport}><i className="fas fa-file-excel" /> Xuất Excel</Button>
        </div>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã NV</th>
                  <th>Họ tên</th>
                  <th>Đơn vị</th>
                  <th className={styles.colRight}>Ngày làm</th>
                  <th className={styles.colRight}>Tăng ca (h)</th>
                  <th>Chuyên cần</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((r, i) => (
                  <tr key={r.employeeId ?? i}>
                    <td>{r.employeeCode ?? '—'}</td>
                    <td>{r.employeeName ?? '—'}</td>
                    <td>{r.departmentName ?? '—'}</td>
                    <td className={styles.colRight}>{r.workingDays ?? 0}</td>
                    <td className={styles.colRight}>{(r.overtimeHours ?? 0) > 0 ? (r.overtimeHours ?? 0).toFixed(1) : '—'}</td>
                    <td>
                      <div className={styles.progressBar}>
                        <div className={styles.progressFill} style={{ width: `${Math.min(100, r.attendanceRate ?? 0)}%` }} />
                      </div>
                      <div className={styles.progressLabel}>{Math.round(r.attendanceRate ?? 0)}%</div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default BaoCaoCongPage;
